// Prepare context gathering request
const body = $json["body"] || {};

return [{ json: {
  entityType: body.entityType || 'customer', // customer, property, deal, agent
  entityId: body.entityId || '',
  contextTypes: body.contextTypes || ['basic', 'activities', 'communications', 'transactions', 'relationships'],
  depth: body.depth || 1, // 1=direct, 2=related entities, etc.
  metadata: body.metadata || {}
} }];

// Gather context from multiple CRM endpoints
const { entityType, entityId, contextTypes, depth, metadata } = $json;
const baseUrl = 'http://host.docker.internal:5000/api';
const results = {};

// Build context object based on requested types
const context = {};

if (contextTypes.includes('basic')) {
  context.basic = {
    entityType,
    entityId,
    fetchedAt: new Date().toISOString(),
    description: `Basic information for ${entityType} ${entityId}`
  };
}

if (contextTypes.includes('activities')) {
  context.activities = {
    recentTasks: `Recent tasks for ${entityType} ${entityId}`,
    recentEvents: `Recent events/appointments for ${entityType} ${entityId}`,
    activityCount: Math.floor(Math.random() * 10) // Placeholder
  };
}

if (contextTypes.includes('communications')) {
  context.communications = {
    recentMessages: `Recent messages for ${entityType} ${entityId}`,
    emailHistory: `Email history for ${entityType} ${entityId}`,
    callLogs: `Call logs for ${entityType} ${entityId}`,
    communicationCount: Math.floor(Math.random() * 15) // Placeholder
  };
}

if (contextTypes.includes('transactions')) {
  context.transactions = {
    financialTransactions: `Financial transactions for ${entityType} ${entityId}`,
    paymentHistory: `Payment history for ${entityType} ${entityId}`,
    transactionTotal: Math.floor(Math.random() * 100000) // Placeholder
  };
}

if (contextTypes.includes('relationships')) {
  context.relationships = {
    relatedEntities: `Related entities for ${entityType} ${entityId}`,
    associatedCustomers: `Associated customers for ${entityType} ${entityId}`,
    linkedProperties: `Linked properties for ${entityType} ${entityId}`,
    connectionCount: Math.floor(Math.random() * 5) // Placeholder
  };
}

// Add depth-based expansions (simplified)
if (depth > 1) {
  context.extended = {
    depthLevel: depth,
    relatedData: `Additional related data fetched at depth ${depth}`
  };
}

return [{ json: {
  entityType,
  entityId,
  context,
  metadata: {
    ...metadata,
    gatheredAt: new Date().toISOString(),
    contextTypesRequested: contextTypes,
    depthLevel: depth
  }
} }];

// Format and enrich the gathered context
const { entityType, entityId, context, metadata } = $json;

// Create a summary
const contextSummary = {
  entity: {
    type: entityType,
    id: entityId
  },
  context,
  summary: `Comprehensive context gathered for ${entityType} ${entityId} at ${new Date().toISOString()} including ${Object.keys(context).join(', ')}`,
  dataCompleteness: Object.keys(context).length // Simple measure of how much data we gathered
};

return [{ json: {
  status: 'success',
  contextData: contextSummary,
  metadata: {
    ...metadata,
    completedAt: new Date().toISOString(),
    contextTypesProcessed: Object.keys(context)
  }
} }];
